// ---------- Union Find ----------
typedef struct {int parent, rank;} DSU;
static DSU *dsu;
int find_set(int v){return dsu[v].parent==v?v: (dsu[v].parent=find_set(dsu[v].parent));}
void union_sets(int a,int b){a=find_set(a);b=find_set(b);if(a!=b){if(dsu[a].rank<b) a=b; dsu[b].parent=a; if(dsu[a].rank==dsu[b].rank) dsu[a].rank++;}}

// ---------- Hash for walls ----------
typedef struct {int a,b; struct Node *next;} Node;
