static int HSIZE=2000003; // prime > 2*W
unsigned int wall_hash_key(int x1,int y1,int x2,int y2){unsigned int h = ((unsigned int)x1*1009u + y1)*1000003u + ((unsigned int)x2*1009u + y2); return h % HSIZE;}
int wall_exists(int x1,int y1,int x2,int y2){unsigned int h=wall_hash_key(x1,y1,x2,y2); for(Node*cur=wallHash[h];cur;cur=cur->next) if(cur->a==x1 && cur->b==y1 && cur->next->a==x2 && cur->next->b==y2) return 1; return 0;}
void add_wall(int x1,int y1,int x2,int y2){unsigned int h=wall_hash_key(x1,y1,x2,y2); Node* n= (Node*)malloc(sizeof(Node)); n->a=x1; n->b=y1; n->next=wallHash[h]; wallHash[h]=n; // store both directions in same bucket for simplicity
    h=wall_hash_key(x2,y2,x1,y1); n= (Node*)malloc(sizeof(Node)); n->a=x2; n->b=y2; n->next=wallHash[h]; wallHash[h]=n; }

